"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[567],{5226:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"Documenta\xe7\xe3o Acad\xeamica","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Sprint 01","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Entendimento do Neg\xf3cio","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Matriz de Risco","href":"/entendimento-do-negocio/matriz-de-risco","docId":"Documentacao/Sprint01/Negocios/matrizDeRisco","unlisted":false},{"type":"link","label":"Canvas Proposta de Valor","href":"/entendimento-do-negocio/canvas-proposta-de-valor","docId":"Documentacao/Sprint01/Negocios/cpv","unlisted":false}],"href":"/entendimento-do-negocio"},{"type":"category","label":"UX Research","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Imers\xe3o Preliminar","href":"/ux-research/imersao-preliminar","docId":"Documentacao/Sprint01/UX Research/research","unlisted":false},{"type":"link","label":"Personas","href":"/ux-research/personas","docId":"Documentacao/Sprint01/UX Research/personas","unlisted":false},{"type":"link","label":"Jornada do Usu\xe1rio","href":"/ux-research/jornada","docId":"Documentacao/Sprint01/UX Research/jornada","unlisted":false}],"href":"/ux-research"},{"type":"category","label":"Arquitetura do sistema","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Requisitos Funcionais e N\xe3o Funcionais","href":"/arquitetura-do-sistema/requisitos-rf-rnf","docId":"Documentacao/Sprint01/arquitetura/elicitacaoRFeRNF","unlisted":false},{"type":"link","label":"Proposta de arquitetura do sistema","href":"/arquitetura-do-sistema/proposta-de-arquitetura","docId":"Documentacao/Sprint01/arquitetura/propostaDeArquitetura","unlisted":false}],"href":"/arquitetura-do-sistema"}],"href":"/Documentacao/Sprint01/Sprint01"}],"href":"/"}]},"docs":{"Documentacao/README":{"id":"Documentacao/README","title":"Documenta\xe7\xe3o Acad\xeamica","description":"Integrantes do grupo","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/arquitetura/elicitacaoRFeRNF":{"id":"Documentacao/Sprint01/arquitetura/elicitacaoRFeRNF","title":"Requisitos Funcionais e N\xe3o Funcionais","description":"Requisitos Funcionais","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/arquitetura/propostaDeArquitetura":{"id":"Documentacao/Sprint01/arquitetura/propostaDeArquitetura","title":"Proposta de arquitetura do sistema","description":"&emsp;Segundo a norma ISO/IEC/IEEE 42010, publicada em 2011 e atualizada em 2022, \\"a arquitetura de software s\xe3o os conceitos fundamentais de um sistema, incluindo seus elementos, relacionamentos e os princ\xedpios para seu projeto e evolu\xe7\xe3o\\". Essa defini\xe7\xe3o exprime os principais aspectos da arquitetura de um software, ou seja, o projeto que cont\xe9m os elementos e suas rela\xe7\xf5es dentro do sistema. Dessa forma, a arquitetura embarca os princ\xedpios que regem a forma como todos os elementos do software se conectam, de forma detalhada e clara, pois \xe9 o esqueleto do sistema inteiro. Al\xe9m disso, a arquitetura de um sistema abarca informa\xe7\xf5es como os tipos de conex\xf5es e trocas de dados entre os componentes.","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/arquitetura/README":{"id":"Documentacao/Sprint01/arquitetura/README","title":"Arquitetura do sistema","description":"","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/Negocios/cpv":{"id":"Documentacao/Sprint01/Negocios/cpv","title":"Canvas Proposta de Valor","description":"&emsp;O Canvas de Proposta de Valor (CPV) \xe9 uma ferramenta de muita import\xe2ncia para o desenvolvimento de projetos, uma vez que permite entender as necessidades do cliente ao analisar suas tarefas atuais, identificar as dores relacionadas a esse processo e definir como o produto ou servi\xe7o pode solucionar esses problemas (PLAY STUDIO, 2023).","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/Negocios/matrizDeRisco":{"id":"Documentacao/Sprint01/Negocios/matrizDeRisco","title":"Matriz de Risco","description":"&emsp;A Matriz de Riscos \xe9 uma ferramenta muito utilizada no gerenciamento estrat\xe9gico de riscos, tendo como principais finalidades a identifica\xe7\xe3o, avalia\xe7\xe3o e prioriza\xe7\xe3o dos riscos que envolvem projetos ou opera\xe7\xf5es de uma organiza\xe7\xe3o, com base em sua probabilidade, de ocorr\xeancia e no impacto potencial, apresentando essas informa\xe7\xf5es de maneira visual.","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/Negocios/README":{"id":"Documentacao/Sprint01/Negocios/README","title":"Entendimento do Neg\xf3cio","description":"&emsp; Esta \xe9 a parte respons\xe1vel pelo entendimento das demandas do neg\xf3cio. Nesta etapa, define-se a dor a ser resolvida, os objetivos e os principais stakeholders que ser\xe3o afetados pelo projeto. Al\xe9m disso, compreende-se, nesta etapa, quais s\xe3o os processos que podem impulsionar ou limitar o projeto, definindo-se os requisitos organizacionais. Apesar de ser um ponto de vista independente dos demais, o ponto de vista de neg\xf3cios deve direcionar a condu\xe7\xe3o do projeto.","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/README":{"id":"Documentacao/Sprint01/README","title":"Sprint 01","description":"","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/UX Research/jornada":{"id":"Documentacao/Sprint01/UX Research/jornada","title":"Jornada do Usu\xe1rio","description":"&emsp;Durante o in\xedcio de um projeto, a cria\xe7\xe3o de uma jornada de usu\xe1rio para suas personas permite que a equipe passe das suposi\xe7\xf5es sobre as atitudes do usu\xe1rio do sistema e se ponha em seu lugar. Isso ajuda na identifica\xe7\xe3o de motiva\xe7\xf5es, desafios e comportamentos de cada indiv\xedduo em cada ocasi\xe3o.","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/UX Research/personas":{"id":"Documentacao/Sprint01/UX Research/personas","title":"Personas","description":"&emsp; A cria\xe7\xe3o de personas \xe9 uma ferramenta essencial para compreender os usu\xe1rios do sistema, permitindo o desenvolvimento de solu\xe7\xf5es mais alinhadas \xe0s suas necessidades. Por meio de pesquisas de campo, foram identificadas duas principais fun\xe7\xf5es atuantes no processo de montagem da fita m\xe9dica: o farmac\xeautico e o t\xe9cnico em farm\xe1cia. Esses profissionais desempenham pap\xe9is fundamentais na valida\xe7\xe3o, separa\xe7\xe3o e registro de medicamentos, garantindo precis\xe3o e seguran\xe7a na administra\xe7\xe3o dos tratamentos.","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/UX Research/README":{"id":"Documentacao/Sprint01/UX Research/README","title":"UX Research","description":"&emsp; Esta \xe9 a parte respons\xe1vel pelo estudo aprofundado do usu\xe1rio e das suas intera\xe7\xf5es com o produto ou servi\xe7o. A pesquisa de experi\xeancia do usu\xe1rio (UX) tem como objetivo central compreender as necessidades, desejos, comportamentos e pontos de dor do p\xfablico-alvo, permitindo que solu\xe7\xf5es mais eficazes sejam projetadas para atend\xea-los.","sidebar":"tutorialSidebar"},"Documentacao/Sprint01/UX Research/research":{"id":"Documentacao/Sprint01/UX Research/research","title":"Imers\xe3o Preliminar","description":"Imers\xe3o Preliminar","sidebar":"tutorialSidebar"}}}}')}}]);